module RefModule(
    output X,
    input  A,
    input  B,
    input  C,
    input  D
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire obf_AB, CD, ABCD;

    // Modified to use a simple XOR operation instead
    assign obf_AB = A ^ B;
    assign CD = C ^ D;
    assign ABCD = obf_AB ^ CD;

    assign X = ABCD;

endmodule
